#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int primMST(vector<vector<int>>& edges, int V) {
        vector<vector<pair<int, int>>> graph(V);
        for (auto& edge : edges) {
            int u = edge[0], v = edge[1], w = edge[2];
            graph[u].emplace_back(v, w);
            graph[v].emplace_back(u, w);
        }
        vector<bool> visited(V, false);
        vector<int> weights(V, INT_MAX);
        weights[0] = 0;
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
        pq.emplace(0, 0);
        int mst_weight = 0;
        while (!pq.empty()) {
            auto top = pq.top();
            pq.pop();
            int w = top.first, node = top.second;
            if (visited[node])
                continue;
            visited[node] = true;
            mst_weight += w;
            for (auto& neighbor : graph[node]) {
                int neighbor_node = neighbor.first, edge_weight = neighbor.second;
                if (!visited[neighbor_node] && edge_weight < weights[neighbor_node]) {
                    weights[neighbor_node] = edge_weight;
                    pq.emplace(edge_weight, neighbor_node);
                }
            }
        }
        return mst_weight;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(3));
    for (int i = 0; i < E; i++)
        cin >> edges[i][0] >> edges[i][1] >> edges[i][2];
    Solution sol;
    int ans = sol.primMST(edges, V);
    cout << ans << '\n';
    return 0;
}
